initialization.per_particle_initialization:
variable.particle_lifetime = math.random(0.5, 1.5);
variable.particle_age = 0.0;
variable.particle_size = math.random(0.3, 0.8);
variable.horizontal_vel = math.random(-2, 2);
variable.vertical_vel = math.random(1, 3);

update.per_update_tick:
variable.particle_age += 0.016;
variable.particle_x += variable.horizontal_vel * 0.016;
variable.particle_y += variable.vertical_vel * 0.016;
variable.particle_z += math.random(-1, 1) * 0.016;
variable.horizontal_vel *= 0.95;
variable.vertical_vel *= 0.98;
